import React, { useState } from 'react';

const TaskForm = ({ onTaskAdded }) => {
  // 1. These define the "State" (the missing variables)
  const [topic, setTopic] = useState('');
  const [description, setDescription] = useState('');

  // 2. This defines the "handleSubmit" function
const handleSubmit = async (e) => {
    e.preventDefault();
    if (!topic || !description) return alert("Please fill in both fields");

    try {
      // 1. This is the actual "Call" to your backend
      const response = await axios.post('/api/tasks', { 
        title: topic,        // Note: Check if your backend model uses 'title' or 'topic'
        description: description 
      });

      if (response.status === 201 || response.status === 200) {
        // 2. This tells the parent (Tasks.jsx) to refresh the list
        onTaskAdded(); 

        // 3. Clear the form
        setTopic('');
        setDescription('');
        console.log("Debate Published successfully!");
      }
    } catch (error) {
      console.error("Error posting debate:", error);
      alert("Failed to post debate. Check if backend is running!");
    }
  };

  return (
    <div className="bg-slate-100 p-8 rounded-xl shadow-inner border border-slate-200 mb-8">
      <h2 className="text-slate-800 text-2xl font-bold mb-6 tracking-tight">Start a New Debate</h2>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Debate Topic</label>
          <input 
            type="text" 
            placeholder="e.g., AI is the future of Education..." 
            className="w-full p-3 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-slate-400 focus:border-transparent transition text-slate-900"
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Opening Argument</label>
          <textarea 
            placeholder="Provide context for the debate..." 
            className="w-full p-3 bg-white border border-slate-300 rounded-lg h-32 focus:ring-2 focus:ring-slate-400 focus:border-transparent transition text-slate-900"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
          />
        </div>

        <button 
          type="submit" 
          className="w-full bg-slate-800 text-white p-3 rounded-lg font-bold hover:bg-slate-700 active:bg-slate-900 transition-all shadow-md"
        >
          Open Debate
        </button>
      </form>
    </div>
  );
};

// 3. This is the "Export" that fixes the first error
export default TaskForm;
